def prod_signs(arr):
    if not arr:
        return None
    sum_magnitudes = 0
    sign_product = 1
    for num in arr:
        sum_magnitudes += abs(num)
        if num == 0:
            sign_product = 0
        elif num < 0:
            sign_product *= -1
    return sum_magnitudes * sign_product

