def f(n):
    result = []
    for i in range(n):
        if (i + 1) % 2 == 0:
            fact = 1
            for j in range(1, i + 2):
                fact *= j
            result.append(fact)
        else:
            sum_val = sum(range(1, i + 2))
            result.append(sum_val)
    return result

